::-webkit-scrollbar {
  width: 5px;
  height: 5px;
}
::-webkit-scrollbar-track {
  background: #f1f1f1;
  border-radius: 10px;
}
::-webkit-scrollbar-thumb {
  background: #888;
  border-radius: 10px;
}
::-webkit-scrollbar-thumb:hover {
  background: #555;
}
.container-menu-one {
  overflow-y: auto;
  scrollbar-width: none;
  -ms-overflow-style: none;
}
.container-menu-one::-webkit-scrollbar {
  display: none;
  width: 0;
  height: 0;
}

.toggle-cont {
  --primary: #54a8fc;
  --light: #d9d9d9;
  --dark: #121212;
  --gray: #414344;
  position: relative;
  z-index: 10;
  width: fit-content;
  height: var(--toggle-height, 50px);
  transform: translateY(-5px);
  border-radius: 9999px;
}
.toggle-cont .toggle-input {
  display: none;
}
.toggle-cont .toggle-label {
  --gap: 5px;
  --width: var(--toggle-width, 50px);
  cursor: pointer;
  position: relative;
  display: inline-block;
  padding: var(--toggle-padding, 0.5rem);
  width: calc((var(--width) + var(--gap)) * 2);
  height: 100%;
  background-color: var(--dark);
  border: 1px solid #777777;
  border-bottom: 0;
  border-radius: 9999px;
  box-sizing: content-box;
  transition: all 0.3s ease-in-out;
}
.toggle-before {
  position: absolute;
  z-index: -10;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: calc(100% + 0.5rem);
  height: calc(100% + 0.5rem);
  background-color: var(--gray);
  border: 1px solid #777777;
  border-bottom: 0;
  border-radius: 9999px;
  transition: all 0.3s ease-in-out;
}
.toggle-after {
  position: absolute;
  z-index: -10;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 100%;
  height: 100%;
  background-image: radial-gradient(circle at 50% -100%, #3a9bfc 0%, #0c0c0c 80%);
  border-radius: 9999px;
}
.toggle-cont .toggle-label .cont-icon {
  display: flex;
  justify-content: center;
  align-items: center;
  position: relative;
  width: var(--width);
  height: var(--toggle-height, 50px);
  background-image: radial-gradient(circle at 50% 0%, #666666 0%, var(--gray) 100%);
  border: 1px solid #aaaaaa;
  border-bottom: 0;
  border-radius: 9999px;
  box-shadow: inset 0 -0.15rem 0.15rem var(--primary), inset 0 0 0.5rem 0.75rem var(--second);
  transition: transform 0.3s ease-in-out;
}
.cont-icon {
  overflow: clip;
  position: relative;
}
.cont-icon .sparkle {
  position: absolute;
  top: 50%;
  left: 50%;
  display: block;
  width: calc(var(--width) * 1px);
  aspect-ratio: 1;
  background-color: var(--light);
  border-radius: 50%;
  transform-origin: 50% 50%;
  rotate: calc(1deg * var(--deg));
  transform: translate(-50%, -50%);
  animation: sparkle calc(100s / var(--duration)) linear calc(0s / var(--duration)) infinite;
}
@keyframes sparkle {
  to {
    width: calc(var(--width) * 0.5px);
    transform: translate(2000%, -50%);
  }
}
.cont-icon .icon {
  width: var(--icon-size, 1.1rem);
  fill: var(--light);
}
.toggle-cont:has(.toggle-input:checked) {
  --checked: true;
}
@container style(--checked: true) {
  .toggle-cont .toggle-label {
    background-color: #41434400;
    border: 1px solid #3d6970;
    border-bottom: 0;
  }
  .toggle-cont .toggle-before {
    box-shadow: 0 1rem 2.5rem -2rem #0080ff;
  }
  .toggle-cont .toggle-label .cont-icon {
    overflow: visible;
    background-image: radial-gradient(circle at 50% 0%, #045ab1 0%, var(--primary) 100%);
    border: 1px solid var(--primary);
    border-bottom: 0;
    transform: translateX(calc((var(--gap) * 2) + 100%)) rotate(-225deg);
  }
  .toggle-cont .toggle-label .cont-icon .sparkle {
    z-index: -10;
    width: calc(var(--width) * 1.5px);
    background-color: #acacac;
    animation: sparkle calc(100s / var(--duration)) linear calc(10s / var(--duration)) infinite;
  }
  @keyframes sparkle {
    to {
      width: calc(var(--width) * 1px);
      transform: translate(5000%, -50%);
    }
  }
}

.popup-layout {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(255, 255, 255, 0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
}
.popup-layout-content {
  border-radius: 8px;
  overflow: hidden;
  background-color: #fff;
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-width: 70%;
  max-height: 70%;
  box-shadow: rgba(14, 30, 37, 0.12) 0px 2px 4px 0px, rgba(14, 30, 37, 0.32) 0px 2px 16px 0px;
  z-index: 9999;
}
.popup-layout-content-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 12px 16px;
  font-size: 18px;
  font-weight: 600;
  background-color: #efefef;
}
.popup-layout-content-body {
  padding: 0 16px 10px 16px;
  overflow: auto;
  flex: 1;
}
@media (max-width: 768px) {
  .popup-layout-content-header {
    font-size: 16px;
    padding: 10px 12px;
  }
  .popup-layout-content-header svg {
    width: 20px;
    height: 20px;
  }
}
@media (max-width: 480px) {
  .popup-layout-content-header {
    font-size: 14px;
    padding: 8px 10px;
  }
  .popup-layout-content-header svg {
    width: 18px;
    height: 18px;
  }
  .popup-layout-content {
    max-width: 100%;
    max-height: 100%;
    width: 100%;
    height: 100%;
    border-radius: 0;
  }
}

.popup-color-image__container {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.popup-color-image__canvas {
  width: 350px;
  object-fit: cover;
  cursor: crosshair;
}
.popup-color-image__color-info {
  display: flex;
  gap: 20px;
  align-items: center;
  width: 100%;
}
.popup-color-image__color-info__color {
  width: 30px;
  height: 30px;
  border: 1px solid #ccc;
}
.popup-color-image__color-info__text {
  display: flex;
  flex: 1;
  border: 1px solid #ccc;
  padding: 5px 10px;
  border-radius: 5px;
  justify-content: space-between;
  align-items: center;
  font-weight: 400;
}
.popup-color-image__button {
  outline: none;
  background-color: white;
  color: #1d4ed8;
  border: 2px solid #1d4ed8;
  border-radius: 5px;
  padding: 7px 10px;
  cursor: pointer;
}
.popup-color-image__title {
  color: #1d4ed8;
  display: flex;
  align-items: center;
  gap: 10px;
  cursor: pointer;
  font-weight: 400;
}

.container-form-input {
  position: relative;
  flex: 1;
  display: flex;
  border: 1px solid #ccc;
  border-radius: 4px;
  align-items: center;
  outline: none;
}
.input-form-input {
  flex: 1;
  padding: 6px;
  outline: none;
  border: none;
  font-size: 13px;
  color: #444444;
}

.container-form-range {
  position: relative;
  width: 100%;
  display: flex;
}
.input-form-range {
  flex: 1;
  border-radius: 4px;
  border: 1px solid #ccc;
  outline: none;
  font-size: 13px;
  color: #444444;
  z-index: 1;
}

.container-form-select {
  position: relative;
  width: 100%;
  display: flex;
}
.input-form-select {
  flex: 1;
  border-radius: 4px;
  padding: 6px 4px;
  border: 1px solid #ccc;
  outline: none;
  font-size: 13px;
  color: #444444;
  width: 100%;
}
.input-form-select:hover {
  border-color: #9ca3af;
}
.options-list-select {
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  background: white;
  border: 1px solid #ccc;
  border-radius: 4px;
  margin: 0;
  padding: 8px 0;
  list-style: none;
  max-height: 200px;
  overflow-y: auto;
  z-index: 1000;
}
.option-item-select {
  padding: 8px;
  cursor: pointer;
}
.option-item-select:hover {
  background-color: #f0f0f0;
}
.icon-form-select {
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 12px;
  color: #888;
  z-index: 100;
}

.popup-select-icon {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.popup-select-icon-item-container {
  display: flex;
  flex-wrap: wrap;
  justify-content: space-between;
  gap: 6px;
  overflow-y: auto;
  flex: 1;
}
.popup-select-icon-item:hover {
  border-radius: 4px;
  background-color: #c7c7c7;
}
.popup-select-icon-search {
  display: flex;
  align-items: center;
  gap: 10px;
}
.popup-select-icon-upload-label {
  display: inline-flex;
  align-items: center;
  color: #575757;
  border: 1px solid #575757;
  border-radius: 6px;
  cursor: pointer;
  padding: 3px 5px;
  font-size: 14px;
  transition: background-color 0.2s ease;
  gap: 6px;
}
.popup-select-icon-upload-label:hover {
  background-color: #57575791;
  color: #fff;
}
.popup-select-icon-upload-input {
  display: none;
}

.container-form-select-icon {
  position: relative;
  width: 100%;
  display: flex;
}
.input-form-select-icon {
  display: flex;
  align-items: center;
  width: 100%;
  border: 1px solid #ccc;
  padding: 8px 4px;
  border-radius: 4px;
  gap: 4px;
  background-color: white;
}
.input-form-select-icon:hover {
  border-color: #9ca3af;
}
.input-form-select-icon input {
  flex: 1;
  border-radius: 4px;
  outline: none;
  font-size: 13px;
  border: 0;
}
.options-list-icon {
  position: absolute;
  top: 100%;
  width: 200px;
  left: 0;
  right: 0;
  border: 1px solid #ccc;
  background-color: #fff;
  border-radius: 4px;
  margin: 0;
  padding: 8px 0;
  list-style: none;
  max-height: 200px;
  overflow-y: auto;
  z-index: 1000;
  display: flex;
  flex-wrap: wrap;
}
.option-item-icon {
  padding: 8px;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 16px;
}
.option-item-icon:hover {
  background-color: #f0f0f0;
}

.popup-enter-license__container {
  width: 400px;
}
.popup-enter-license__header {
  margin-bottom: 24px;
}
.popup-enter-license__title {
  font-size: 24px;
  font-weight: bold;
  color: #1f2937;
  margin: 0 0 8px 0;
}
.popup-enter-license__description {
  color: #6b7280;
  margin: 0;
  font-size: 14px;
}
.popup-enter-license__form-group {
  margin-bottom: 16px;
}
.popup-enter-license__label {
  display: block;
  font-size: 14px;
  font-weight: 500;
  color: #374151;
  margin-bottom: 8px;
}
.popup-enter-license__textarea {
  width: 100%;
  padding: 8px 12px;
  border: 1px solid #d1d5db;
  border-radius: 8px;
  font-size: 18px;
  resize: none;
  transition: all 0.2s ease;
  box-sizing: border-box;
}
.popup-enter-license__textarea:focus {
  outline: none;
  border-color: #3b82f6;
  box-shadow: 0 0 0 2px rgba(59, 130, 246, 0.1);
}
.popup-enter-license__textarea--error {
  border-color: #ef4444;
}
.popup-enter-license__textarea:disabled {
  background-color: #f9fafb;
  cursor: not-allowed;
  opacity: 0.6;
}
.popup-enter-license__error {
  display: flex;
  align-items: center;
  color: #ef4444;
  font-size: 14px;
  margin-top: 8px;
}
.popup-enter-license__error-icon {
  width: 16px;
  height: 16px;
  margin-right: 4px;
  flex-shrink: 0;
}
.popup-enter-license__actions {
  display: flex;
  justify-content: flex-end;
  gap: 12px;
}
.popup-enter-license__button {
  padding: 8px 16px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
  border: none;
  display: flex;
  align-items: center;
  gap: 8px;
}
.popup-enter-license__button:disabled {
  opacity: 0.5;
  cursor: not-allowed;
}
.popup-enter-license__button--cancel {
  background-color: transparent;
  color: #6b7280;
  border: 1px solid #d1d5db;
}
.popup-enter-license__button--cancel:hover:not(:disabled) {
  background-color: #f9fafb;
}
.popup-enter-license__button--cancel:focus {
  outline: none;
  box-shadow: 0 0 0 2px rgba(107, 114, 128, 0.2);
}
.popup-enter-license__button--confirm {
  background-color: #3b82f6;
  color: white;
  padding: 8px 24px;
}
.popup-enter-license__button--confirm:hover:not(:disabled) {
  background-color: #2563eb;
}
.popup-enter-license__button--confirm:focus {
  outline: none;
  box-shadow: 0 0 0 2px rgba(59, 130, 246, 0.2);
}
.popup-enter-license__spinner {
  width: 16px;
  height: 16px;
  animation: spin 1s linear infinite;
}
.popup-enter-license__spinner-circle {
  opacity: 0.25;
}
.popup-enter-license__spinner-path {
  opacity: 0.75;
}
@keyframes spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}
.popup-enter-license__success {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  padding: 32px;
  text-align: center;
  min-width: 300px;
}
.popup-enter-license__success-icon {
  width: 64px;
  height: 64px;
  background-color: #dcfce7;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 16px;
}
.popup-enter-license__check-icon {
  width: 32px;
  height: 32px;
  color: #22c55e;
}
.popup-enter-license__success-title {
  font-size: 20px;
  font-weight: 600;
  color: #1f2937;
  margin: 0 0 8px 0;
}
.popup-enter-license__success-message {
  color: #6b7280;
  margin: 0 0 16px 0;
  font-size: 14px;
}
.popup-enter-license__loading-dots {
  display: flex;
  gap: 4px;
}
.popup-enter-license__dot {
  width: 8px;
  height: 8px;
  background-color: #22c55e;
  border-radius: 50%;
  animation: bounce 1.4s infinite ease-in-out;
}
.popup-enter-license__dot--1 {
  animation-delay: -0.32s;
}
.popup-enter-license__dot--2 {
  animation-delay: -0.16s;
}
.popup-enter-license__dot--3 {
  animation-delay: 0s;
}
@keyframes bounce {
  0%,
  80%,
  100% {
    transform: scale(0);
  }
  40% {
    transform: scale(1);
  }
}
@media (max-width: 480px) {
  .popup-enter-license__container {
    width: 100%;
  }
  .popup-enter-license__title {
    font-size: 20px;
  }
  .popup-enter-license__actions {
    flex-direction: column-reverse;
  }
  .popup-enter-license__button {
    width: 100%;
    justify-content: center;
  }
}

.popup-license {
  max-width: 400px;
  border-radius: 12px;
  font-family: "Segoe UI", sans-serif;
  text-align: center;
  animation: fadeIn 0.4s ease-in-out;
  margin-top: 10px;
}
.popup-license p {
  font-size: 15px;
  color: #374151;
  margin-bottom: 24px;
  line-height: 1.5;
}
.popup-license-button {
  display: flex;
  justify-content: center;
  gap: 16px;
}
.popup-license-button button {
  padding: 10px 18px;
  border-radius: 8px;
  font-size: 14px;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.3s ease;
  min-width: 130px;
  border: none;
}
.popup-license-button button:first-child {
  background-color: #1d4ed8;
  color: white;
}
.popup-license-button button:first-child:hover {
  background-color: #1e40af;
  transform: translateY(-2px);
}
.popup-license-button button:last-child {
  background-color: #f3f4f6;
  color: #1f2937;
  border: 1px solid #d1d5db;
}
.popup-license-button button:last-child:hover {
  background-color: #e5e7eb;
  transform: translateY(-2px);
}
@keyframes fadeIn {
  from {
    opacity: 0;
    transform: translateY(8px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.setting-icon-box-setting {
  position: fixed;
  right: 10px;
  top: 20px;
  background-color: #fff;
  border: none;
  border-radius: 50%;
  width: 40px;
  height: 40px;
  display: flex;
  align-items: center;
  justify-content: center;
  box-shadow: 0 2px 5px rgba(0, 0, 0, 0.2);
  cursor: pointer;
  z-index: 999 !important;
}
