  text-align: center;
  text-transform: uppercase;
}
.icon-button-box-setting {
  background: none;
  border: none;
  font-size: 16px;
  cursor: pointer;
  color: black;
  transform: translateY(2px);
}
.container-box-setting-content {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
}
.box-setting-label {
  font-weight: 500;
  text-transform: capitalize;
}
.container-box-setting-footer {
  padding: 8px 16px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
}
.box-setting-button {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 4px 8px;
  font-size: 14px;
  font-weight: 500;
  border-radius: 5px;
  cursor: pointer;
  transition: all 0.3s ease;
