  color: #fff;
}
.text {
  pointer-events: none;
  font-size: 13px;
}

.popup-select-toggle {
  width: 100%;
  height: 100%;
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  overflow-y: auto;
  overflow-x: hidden;
  gap: 10px;
}
.toggle-item {
  height: 60px;
  border-radius: 8px;
  transition: all 0.3s ease;
  border: 1px solid #ccc;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 10px;
}
.toggle-item:hover {
  cursor: pointer;
  border: 1px solid #0275a7;
}

.setting-toggle-wrapper {
  width: 100%;
  max-width: 400px;
  margin: 0 auto;
  position: relative;
}
.setting-toggle-container {
  background: #ffffff;
  border-radius: 16px;
  box-shadow: 0 10px 25px rgba(0, 0, 0, 0.1);
  overflow: hidden;
  border: 1px solid #f1f5f9;
}
.setting-toggle-header {
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  padding: 10px 24px;
  border-bottom: 1px solid #e2e8f0;
}
.setting-toggle-title {
  color: #ffffff;
  font-size: 1.5rem;
  font-weight: 600;
  margin: 0;
  text-align: center;
}
.setting-toggle-content {
  display: flex;
  flex-direction: column;
  gap: 8px;
  background-color: white;
  width: 280px;
}
.setting-toggle-item {
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.setting-toggle-row {
  flex-direction: row !important;
  justify-content: space-between;
  align-items: center;
}
.setting-toggle-label {
  font-size: 0.875rem;
  font-weight: 500;
  color: #374151;
  margin-bottom: 4px;
}
.setting-toggle-label-small {
  font-size: 0.75rem;
  font-weight: 500;
  color: #6b7280;
  margin-bottom: 4px;
}
.setting-toggle-border-group {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 8px;
  background: #f8fafc;
  border-radius: 12px;
  border: 1px solid #e2e8f0;
  margin-top: 8px;
}
.setting-toggle-text-icon {
  display: flex;
  gap: 8px;
  align-items: center;
}
.setting-toggle-border-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}
