}
@media (max-width: 640px) {
  .setting-slide-wrapper {
    max-width: 100%;
    padding: 0 16px;
  }
  .setting-slide-content {
    padding: 20px;
    gap: 12px;
  }
  .setting-slide-header {
    padding: 16px 20px;
  }
  .setting-slide-title {
    font-size: 1.25rem;
  }
  .setting-slide-border-row {
    grid-template-columns: 1fr;
    gap: 12px;
  }
}
.setting-slide-container {
  transition: all 0.3s ease;
}
.setting-slide-container:hover {
  box-shadow: 0 15px 35px rgba(0, 0, 0, 0.15);
}
.setting-slide-border-group {
  animation: slideDown 0.3s ease-out;
}
@keyframes slideDown {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}
.setting-slide-item *:focus {
  outline: 2px solid #3b82f6;
  outline-offset: 2px;
}
.setting-slide-label,
.setting-slide-label-small {
  cursor: pointer;
}
@media (prefers-color-scheme: dark) {
  .setting-slide-container {
    background: #1f2937;
    border-color: #374151;
  }
  .setting-slide-title {
    color: #f9fafb;
  }
  .setting-slide-label,
  .setting-slide-label-small {
    color: #d1d5db;
  }
  .setting-slide-border-group {
    background: #111827;
    border-color: #374151;
  }
  .setting-slide-item select,
  .setting-slide-item input[type="number"] {
    background: #374151;
    border-color: #4b5563;
    color: #f9fafb;
  }
}

.container-slide-component {
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
}
.container-slide-ui {
  width: 90%;
}
.container-slide-setting {
  flex: 0.4;
  height: 100%;
  display: grid;
  place-items: center;
  padding-right: 20px;
}
@media (max-width: 768px) {
  .container-slide-setting {
    flex: 0.6;
  }
}

.main-container {
  width: 100%;
  height: 100vh;
  position: relative;
  box-sizing: border-box;
  overflow: hidden;
}
.grid-container {
  width: 100%;
  height: 100%;
  display: grid;
  grid-template-columns: 1fr 1fr;
  grid-template-rows: 1fr 1fr;
  gap: 24px;
  box-sizing: border-box;
  padding: 48px;
  position: relative;
  z-index: 1;
}
.grid-item {
  cursor: pointer;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  border: 2px solid rgba(255, 255, 255, 0.2);
  color: #272727;
  font-size: 20px;
  font-weight: 700;
  border-radius: 24px;
  text-transform: capitalize;
  padding: 32px;
  gap: 16px;
  text-align: center;
  box-shadow: rgba(0, 0, 0, 0.05) 0px 6px 24px 0px, rgba(0, 0, 0, 0.08) 0px 0px 0px 1px;
  transition: all 0.4s cubic-bezier(0.23, 1, 0.32, 1);
  position: relative;
  overflow: hidden;
  letter-spacing: 0.5px;
}
.grid-item img {
  transform: scale(1.3);
}
.grid-item:hover {
  box-shadow: rgba(99, 99, 99, 0.2) 0px 2px 8px 0px;
  border-color: rgba(255, 255, 255, 0.4);
}
.grid-item:active {
  transition: transform 0.1s ease;
}
.active-component-container {
  width: 100%;
  height: 100%;
  box-sizing: border-box;
  position: relative;
  overflow: hidden;
}
.ui-container-lock {
  height: 100%;
  width: 100%;
  background-color: rgba(255, 255, 255, 0.8);
  display: grid;
  place-items: center;
  position: fixed;
  left: 0;
  top: 0;
  z-index: 99;
}
.ui-container-lock button {
  padding: 5px 10px;
  border: 2px solid #4f46e5;
  border-radius: 5px;
  cursor: pointer;
  color: #4f46e5;
  background-color: transparent;
  outline: none;
}
.ui-container-lock button:hover {
  background-color: #4f46e5;
  color: white;
  transition: all 0.3s ease-in-out;
}
@media (max-width: 768px) {
  .grid-container {
    grid-template-columns: 1fr;
    grid-template-rows: repeat(4, 1fr);
    padding: 24px;
    gap: 20px;
  }
  .grid-item {
    font-size: 18px;
    padding: 24px;
    min-height: 120px;
  }
  .ui-container-lock > div {
    padding: 36px 24px;
    margin: 16px;
  }
}
@media (max-width: 480px) {
  .grid-container {
    padding: 16px;
    gap: 16px;
  }
  .grid-item {
    font-size: 16px;
    padding: 20px;
    min-height: 100px;
  }
}
